module RefModule (
    input clk,
    input reset,
    input up,
    output [2:0] count );reg [2:0] obf_count_reg;

    always @(posedge clk) begin
        if (reset)
            obf_count_reg <= 3'b000;
        else if (up)
            obf_count_reg <= obf_count_reg + 1;
        else
            obf_count_reg <= obf_count_reg - 1;
    end

    assign count = obf_count_reg;

endmodule
